var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"으음......","JPN":"ううん……","ENG":"Ngh...","TWN":"呃嗯……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"케이시! 깨어났구나! 몸은 괜찮아?","JPN":"ケイシー！　目が覚めたんだね！　具合はどう？","ENG":"Kaci! You're awake! How do you feel?","TWN":"卡西！你醒了？身體沒事吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"응, 괜찮아......","JPN":"うん、大丈夫。","ENG":"I'm fine...","TWN":"嗯，我沒事……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그런데...... 스카이는?","JPN":"ところで……スカイは？","ENG":"But... Where's Sky?","TWN":"不過……絲凱呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"스카이? 그게 누군데?","JPN":"スカイ？　それって、誰？","ENG":"Sky? Who's that?","TWN":"絲凱？她是誰？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"어디선가 들어 본 것 같은 이름이긴 한데......","JPN":"どこかで聞いたことがあるような名前なんだけど……","ENG":"I think I heard that name before...","TWN":"我好像在哪兒聽過這個名字……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"스카이 레이필드 말이야. 스카이한테 주려고 소원구슬을 얻자고 했잖아.","JPN":"スカイ・レイフィールドのことね。\\nスカイのために願い玉を手に入れようって話だったじゃない。","ENG":"Sky Layfield. We're trying to get the Wishing Ball for her, remember?","TWN":"絲凱·蕾菲爾德，我們不是說好了要拿到許願珠，然後送給絲凱嗎。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"아, 기억났다! 그 더듬이 녀석!","JPN":"あ、思い出した！　あのアホ毛の子！","ENG":"Oh, I remember! That Antenna girl!","TWN":"啊，我想起來了！是小觸角！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그러고 보니 어디로 갔지? 양호실에 온 뒤로 못 본 것 같은데......?","JPN":"そういえばどこに行ったんだろう？　保健室に来てから見えなくなったよ。","ENG":"Where'd she go? I haven't seen her since we arrived...","TWN":"不過她去哪兒了？來到保健室後，我好像就沒再也看到她了……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"나 여기 있어.","JPN":"私はここにいるよ。","ENG":"I'm here.","TWN":"我在這兒。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"스카이!","JPN":"スカイ！","ENG":"Sky!","TWN":"絲凱！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"케이시, 이제 괜찮아? 내가 괜히 응원한 거 아니지?","JPN":"ケイシー、もう大丈夫？　私が余計に応援したせいじゃないよね？","ENG":"Kaci, are you okay now? You weren't bothered by my cheering, were you?","TWN":"卡西，你沒事了吧？我沒有白白為你加油吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"응. 스카이가 응원 안 해 줬으면, 무서워서 엉엉 울었을 거야.","JPN":"うん。スカイが応援してくれなかったら、怖くて泣いていたと思う。","ENG":"Of course not. If you didn't cheer me on, I would have cried out of fear.","TWN":"嗯，要是沒有絲凱給我加油，我肯定早就嚇得嗚嗚哭了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그런데 스카이, 어디 갔던 거야?","JPN":"ところでスカイ、どこへ行っていたの？","ENG":"But Sky, where have you been?","TWN":"不過絲凱，你剛才去哪兒了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"혼자 다른 데 있지 마. 잊어버릴까 봐 무서웠어.","JPN":"一人で他の所に行かないでね。忘れるんじゃないかと怖かったよ。","ENG":"Don't go away. I was afraid I might forget you.","TWN":"你不要一個人去別的地方，我怕會把你忘了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"응...... 알았어. 고마워.","JPN":"うん……わかった。ありがとう。","ENG":"Okay... I won't. Thank you, Kaci.","TWN":"嗯……我知道了，謝謝你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그런데 너, 어디서 누구랑 싸우다 왔어?","JPN":"ところでスカイ、どっかで誰かとケンカでもしてきたの？","ENG":"Hey, did you get into a fight or something?","TWN":"不過你，在什麼地方跟人打架了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"옷이 흙투성이잖아. 무릎도 까졌고.","JPN":"服が泥だらけじゃない。膝に擦り傷もあるし。","ENG":"Your clothes are covered with dirt. And your knees are all skinned.","TWN":"衣服上全都是土，膝蓋也磕破了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"벼, 별거 아니야. 그냥 넘어져서 그래.","JPN":"た、大したことない。転んだだけなの。","ENG":"I-it's nothing. I fell down is all.","TWN":"沒，沒什麼，只是摔了一跤。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그보다 배고프지? 점심 먹으러 가자!","JPN":"それよりお腹空いたでしょ？　お昼食べに行こう！","ENG":"Look, aren't you guys hungry? Let's go have lunch!","TWN":"那個你餓不餓呀？我們去吃午飯吧！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"아악! 까먹고 있었다!","JPN":"ああっ！　忘れてた！","ENG":"Argh! I forgot about lunch!","TWN":"啊啊！我忘了！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"어쩌지? 점심 시간도 거의 끝났는데......?","JPN":"どうしよう？　お昼の時間もほとんど終わってしまったよ……！","ENG":"What should we do? The lunch break is almost over...","TWN":"怎麼辦？午休時間都快結束了呢……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"지금 급식소에 가도 남은 음식이라곤 피망에 브로콜리뿐일 거야.","JPN":"今食堂に行っても残ってるのはピーマンにブロッコリーだけだろうな。","ENG":"I doubt if there's any food left in the cafeteria except for bell peppers and broccoli.","TWN":"現在就算去食堂，剩下的食物估計也就只有甜椒和花椰菜了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"에너지를 보충하지 않으면 오후 경기 때 문제가 생길 텐데......","JPN":"スタミナをつけないと午後の試合の時に支障が出るかも……","ENG":"If we don't get enough energy, we might have problems in the afternoon games...","TWN":"不補充體力的話，下午的比賽會出問題的……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"미, 미안. 나 때문에......","JPN":"ご、ごめんね。あたしのせいで……","ENG":"S-sorry. It's because of me...","TWN":"對，對不起，都是因為我……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"아, 아니! 그런 뜻은 아니야!","JPN":"あ、違う！　そういう意味じゃない！","ENG":"N-no! That's not what I meant!","TWN":"不，不是的！我不是那個意思！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그까짓 한 끼 굶는다고 경기에 질 리 있겠어?","JPN":"まあ一食抜いたからって試合に負けるはずないしね！","ENG":"Skipping a meal won't make you lose the game!","TWN":"怎麼可能會因為餓一頓就輸掉比賽？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"과학적으로 말도 안 되는 일이지! 하하하!","JPN":"科学的にもあり得ない！　ハハハ！","ENG":"Scientifically speaking, that's nonsense! Hah hah hah!","TWN":"從科學角度講，那是不可能的事！哈哈哈！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"하......","JPN":"ハ……","ENG":"Hah...","TWN":"哈……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_STARVE"},{"id":"L40_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"저기, 점심식사 말인데......","JPN":"あの、お昼ご飯なんだけど……","ENG":"Um, about lunch...","TWN":"那個，午飯……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"실은 어떤 언니가 도시락을 같이 먹자고 했거든.","JPN":"実は、あるお姉ちゃんがお弁当を一緒に食べようって誘ってくれたの。","ENG":"Someone asked me if I could join her for lunch.","TWN":"其實有個姐姐跟我說一起吃便當。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"도시락을 너무 많이 싸 와서 자기들끼리는 다 먹기 힘들대.","JPN":"お弁当をたくさん作ってきたから、自分たちだけで食べきれないんだって。","ENG":"She said she brought too much food, so she and her friends wouldn't be able to eat it all.","TWN":"她說帶了很多便當，她們自己吃不完。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그 거짓말 정말이야?!","JPN":"うそ！　本当に？！","ENG":"Seriously? She actually said that?","TWN":"真的假的？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"으, 응! 정말이야!","JPN":"う、うん！　本当だよ！","ENG":"Y-yes! She did!","TWN":"嗯，嗯！真的！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그런 고마운 언니가 있으면 당장 가서 도와드려야지!","JPN":"そんなありがたいお話をいただいてるなら、今すぐ行って手伝ってあげないと！","ENG":"Then we should go right away and help her!","TWN":"有那麼好的姐姐，我們當然要馬上過去幫忙了！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"음식물을 남기는 건 지구 환경에도 엄청 해롭다고!","JPN":"食べ物を残すのは地球環境にもとても有害なんだ！","ENG":"Wasting food is very bad for the environment!","TWN":"聽說剩飯對地球環境相當有害呢！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"케이시도 괜찮지?","JPN":"ケイシーもいいよね？","ENG":"Kaci, you're okay with this, right?","TWN":"卡西你也沒問題吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"어? 응, 괜찮아......","JPN":"え？　うん、いいよ……","ENG":"Huh? Yes, I guess so...","TWN":"啊？嗯，沒問題……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"들었지? 자자, 그럼 얼른 앞장서!","JPN":"聞いた？　さて、早く行こう！","ENG":"Hear that? Let’s get moving! Hurry!","TWN":"聽到了吧？好了好了，你快點帶路吧！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"이야~ 맛있다~","JPN":"うわーおいしい！","ENG":"Mmm... Yummy!","TWN":"咿呀~真好吃~"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"내가 먹어 본 것 중에 최고의 미트볼이었어.","JPN":"今まで食べたものの中でも最高のミートボールだった。","ENG":"That was the best meatball I've ever had.","TWN":"我從沒吃過這麼好吃的肉丸。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗. 마음에 든다니 다행이네.","JPN":"フフッ、気に入ってもらえて嬉しいわ。","ENG":"Hah hah. I'm glad you liked it.","TWN":"呵呵，你們喜歡就好。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"무기 휘두를 일만 많아서 요리 도구는 만진 적이 많지 않거든.","JPN":"武器を振り回す仕事ばかりで、調理道具は触ったことがあまりなくて。","ENG":"I'm usually out in the battlefield, so I don't cook very often.","TWN":"因為我經常需要舞刀弄棒的，所以下廚的時間並不多。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"요리에 재능이...... 있으신 것 같아요. 정말 맛있어요.","JPN":"料理の才能が……あると思います。本当においしいです。","ENG":"You have talent... in cooking. It's very delicious.","TWN":"您在廚藝方面……好像很有天賦，真的很好吃。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"칭찬 고마워. 아직 많이 있으니까 마음껏 먹어도 돼.","JPN":"褒めてくれてありがとう。まだたくさんあるから好きなだけ食べてもいいからね。","ENG":"Thank you for the compliment. There's still a lot left, so you can eat all you want.","TWN":"多謝誇獎，還有很多，你們多吃點。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"물론 어떤 분은 평가가 조금 까다로운 것 같지만 말이야.","JPN":"でも、とあるお方は少し厳しい評価だけどね。","ENG":"Of course, there seems to be someone who's quite picky.","TWN":"不過，某個人給出的評價似乎有些苛刻。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"애들 상대로 무슨 소릴 하는 거에요?","JPN":"子どもを相手に何を言っているんですか？","ENG":"What are you talking about? They're kids.","TWN":"你和孩子們說什麼呢？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"어른이 그렇게 물어 보면 당연히 맛있다고 하죠.","JPN":"大人にそんなこと聞かれたら、おいしいって答えるのが当たり前でしょう。","ENG":"Of course, they'll say it's delicious if a grown-up has cooked for them.","TWN":"大人那麼問，她們當然會說好吃了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"그거 세뇌 아닌가요? 솔직히 그냥저냥 무난한 수준인데......","JPN":"それって洗脳じゃないですか？　正直に言って普通に無難なレベルなのに……","ENG":"Don't fish for compliments. Honestly, your food is just average...","TWN":"你那是洗腦！說實話，也就是一般般的水準……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그렇게 말하면서 깔끔하게 비웠네. 정말 솔직하지 못하구나, 너.","JPN":"そう言いながらきれいに平らげてくれたわね。本当に素直じゃないんだから。","ENG":"But you cleaned your plate. You're not very honest about your feelings, are you?","TWN":"你嘴裡那麼說，不也吃的精光了嗎。你可真不誠實。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그보다 케이시라고 했지?","JPN":"あ、ケイシーちゃんだったわよね？","ENG":"By the way, Kaci?","TWN":"你叫卡西是吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"왜 옆에 있는 친구 손을 계속 잡고 있을까? 언니한테 알려 줄래?","JPN":"なんで隣にいるお友達の手をずっと握っているの？　お姉さんに教えてくれる？","ENG":"Why are you holding your friend's hand like that? Can you tell me why?","TWN":"你為什麼要緊緊抓著你旁邊那個小姐姐的手呀？可以告訴姐姐嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아...... 이건.......","JPN":"あ……これは……","ENG":"Uh... It's because...","TWN":"啊……這個……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"이렇게 잡고 있지 않으면....... 친구를 잊어버릴 것 같아서요.","JPN":"こうして握っていないと……友達のことを忘れてしまいそうで。","ENG":"If I don't hold her hand like this... I'm afraid I might forget her.","TWN":"我擔心不這樣抓著的話……自己會忘了她。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"흐음. 그런 일이라면 걱정하지 않아도 될 것 같은데.","JPN":"うーん、そんなことなら心配しなくてもいいと思うけど。","ENG":"Hmm... If I were you, I wouldn't worry about it.","TWN":"呃嗯，那樣的話你大可不必擔心。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네? 왜요......?","JPN":"はい？　どうしてですか？","ENG":"Huh? Why?","TWN":"嗯？為什麼……？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"진짜 친구라면 잠깐 잊어버릴 수는 있어도 영원히 사라지지는 않아.","JPN":"本当の友達ならちょっとの間忘れることはあっても、永遠に記憶から消えてしまうことはないのよ。","ENG":"A true friend never goes away, even if you forget about her for a while.","TWN":"因為真正的朋友哪怕暫時忘記，也不會永遠消失。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그 친구가 너한테 소중하면 소중할수록, 더 그렇지.","JPN":"その友達があなたとって大切な存在であるなら尚更ね。","ENG":"Especially if you sincerely care about her.","TWN":"那個朋友對你越重要，越是如此。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"네 친구를 믿어 줘. 네가 잊더라도 네 친구는 널 잊지 않을 테니까.","JPN":"あなたの友達を信じてあげて。あなたは忘れてもその友達はあなたのことを忘れないから。","ENG":"You have to believe in your friend. Even if you forget her, she won't forget you.","TWN":"相信你的朋友，即使你忘了她，你的朋友也不會忘記你的。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그리고 네 친구가 널 잊지 않으면, 너도 분명 다시 떠올릴 수 있을 거야.","JPN":"そして友達があなたのことを忘れなければ、あなたもきっとまた思い出せると思うわ。","ENG":"And if she doesn't forget you, I'm sure you will remember her again.","TWN":"而且，只要你的朋友沒忘了你，你也一定會重新記起她的。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"응, 맞아요! 케이시는 제 소중한 친구니까요!","JPN":"うん、そうだね！　ケイシーは私の大切な友達だもん！","ENG":"Yes, you're right! Because Kaci is my best friend!","TWN":"嗯，沒錯！因為卡西是我很重要的朋友！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"너, 첫 번째 경기에서 점수를 냈던 꼬마지?","JPN":"あなたは最初の試合で点数を稼いでいた子でしょ？","ENG":"Hey, you're that kid who scored in the first game, right?","TWN":"你，是在第一場比賽中得分的那個小孩吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"네? 첫 번째 경기면 꼬리잡기요?","JPN":"うん？　最初の試合ならしっぽ取りゲームのこと？","ENG":"The first game? You mean, Catch The Tail?","TWN":"嗯？第一場比賽的話是說抓尾巴嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"그래. 장애물 달리기에서도 캔을 던져서 나이엘을 넘어트렸고.","JPN":"そう。障害物競走でも缶を投げてナイエルを倒したでしょ。","ENG":"Yeah. And you also threw a soda can that made Naielle trip in the obstacle race.","TWN":"是，在障礙賽跑中扔飲料罐絆倒了奈爾的也是你吧。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"내가 왜 널 기억 못했는지 모르겠네.","JPN":"私がどうしてあなたのことを思い出せなかったのか不思議ね。","ENG":"I don't know why I didn't remember you.","TWN":"不知道為什麼我不記得你了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"혹시 너도 소원구슬을 노리고 있니?","JPN":"もしかしてあなたも願い玉を狙っているの？","ENG":"Tell me, are you also after that Wishing Ball?","TWN":"你也想要許願珠嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그, 그건......","JPN":"そ、それは……","ENG":"Uh, I...","TWN":"這，這個……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"맞아!","JPN":"そうだよ！","ENG":"Yes, that's right.","TWN":"沒錯！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그게 있어야 이 더듬이 녀석의 고민을 해결할 수 있거든.","JPN":"それがあれば、このアホ毛ちゃんの悩みを解決できるんだ。","ENG":"Cause we need that ball to solve Antenna girl's problem.","TWN":"因為只有許願珠才能解決小觸角的問題。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"......그렇구나.","JPN":"……そうなんだ。","ENG":"I see.","TWN":"……原來是這樣。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"같은 팀이니까 앞으로도 같이 협력해야겠지만, 나도 소원구슬은 포기할 수 없거든.","JPN":"同じチームだからこれからも一緒に協力しなきゃいけないけど、私も願い玉は諦められないの。","ENG":"We're in the same team, so I'll continue to cooperate. But I can't give up the Wishing Ball, either.","TWN":"我們是同一個隊的，以後也得一起合作，不過我也不能放棄許願珠。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"소원구슬을 가져가는 게 내 일이라서 말이야.","JPN":"願い玉を手に入れるのが私の仕事だから。","ENG":"It's my job to retrieve it.","TWN":"拿到許願珠是我的任務。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그런가요......?","JPN":"そうなの……？","ENG":"It is?","TWN":"是嗎……？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"그래. 그러니까 소원구슬을 손에 넣으려면 아주 열심히 해야 할 거야.","JPN":"そうなの。だから願い玉を手に入れるためには、全力で頑張らないと私に取られちゃうよ？","ENG":"Yes. So you should try hard, if you want to get that ball.","TWN":"是啊，所以你要是想拿到許願珠，必須非常努力才行。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"난 실력이 꽤 좋은 편이고......","JPN":"私の実力はかなりいいし……","ENG":"I'm very athletic...","TWN":"因為我的實力相當不錯……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"가지고 싶은 건 가져야 직성이 풀리는 성격이거든.","JPN":"欲しいものは手に入れないと気が済まない性格なの。","ENG":"And I always get what I want.","TWN":"而且我是想要的東西一定要得到手才會善罷甘休哦。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"으웅......","JPN":"ううん……","ENG":"Mm...","TWN":"嗯嗚……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그, 그치만 저도, 친구들이랑 약속했는데......","JPN":"で、でも私も、友達と約束したし……","ENG":"B-but, I also promised my friends...","TWN":"可，可是，我也已經跟朋友們約好了……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"<color=#ffd34c>운영 위원회 대신 알려드립니다!</color>","JPN":"<color=#ffd34c>運営委員会に代わってお知らせします！</color>","ENG":"<color=#ffd34c>This is a message from the organizing committee!</color>","TWN":"<color=#ffd34c>通知，播放管委會的通知！</color>"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"<color=#ffd34c>곧 점심시간이 끝나고 다음 경기가 시작될 거예요!</color>","JPN":"<color=#ffd34c>もうすぐお昼休憩時間が終わり、次の試合が始まります！</color>","ENG":"<color=#ffd34c>The lunch break is about to end, and the next game will begin shortly!</color>","TWN":"<color=#ffd34c>午休時間即將結束，下場比賽馬上就要開始了！</color>"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"<color=#ffd34c>학생 여러분은 모두 경기장으로 모여 주세요!</color>","JPN":"<color=#ffd34c>生徒の皆さんは全員競技場に集まってください！</color>","ENG":"<color=#ffd34c>All students, please meet us in the stadium!</color>","TWN":"<color=#ffd34c>請各位同學都到體育場上集合！</color>"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"......뭐, 그렇다고 벌써부터 겁먹고 포기하진 않아도 돼.","JPN":"まぁ、だからといって最初から怖がって諦める必要はないよ。","ENG":"Well, you don't need to get scared and give up already.","TWN":"……嗯，不過就算是這樣，也不用現在就開始膽怯放棄。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"그런 사람이랑 같은 팀이니까, 친구들과의 약속을 지키려면 잘 이용해 보란 뜻이니까.","JPN":"そんな人と同じチームなんだから、\\n友達との約束を守るためにうまく利用してみなさいっていう意味だから。","ENG":"I just wanted you to know about me, and to find a way to use me to keep your promise.","TWN":"我的意思是說既然跟那種人分在一個隊裡，要想遵守跟朋友們的約定，就要好好利用。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"가자. 구슬을 얻으려면 다음 경기도 이겨야지.","JPN":"行こう。玉を手に入れるには次の試合も勝たないと。","ENG":"Let's go. We must win the next game to get the ball.","TWN":"走吧，為了拿到許願珠，下場比賽也要贏才行。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"......아, 네!","JPN":"……あっ、うん！","ENG":"Oh... right! Let's go!","TWN":"……啊，是！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};